using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class CustomersTraining : TrainingContentBase
{
    public CustomersTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Customers Overview",
            Slug = "customers-overview",
            Summary = "What the Customers module does, the 9-tab detail page, contacts, addresses, credit management, and how customers connect to quotes, orders, jobs, and invoices.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/customers"]""",
            Tags = """["customers","contacts","addresses","credit"]""",
            ContentJson = """{"body":"## Customers Overview\n\nThe Customers module is your central customer relationship hub. It tracks every customer your shop works with — their contact people, addresses, credit status, estimates, quotes, sales orders, jobs, invoices, and full activity history. Every customer gets a dedicated detail page with 10 tabs that give you a 360-degree view of the relationship.\n\n### Customer List Page\n\nThe main `/customers` page shows all customers in a searchable, sortable data table. You can filter by active/inactive status and search by name, company, email, or phone. Click any row to navigate to that customer's detail page. The Add Customer button opens a quick-create dialog with name, company name, email, and phone fields.\n\n### Customer Detail Page — 10 Tabs\n\nEvery customer detail page lives at `/customers/:id/:tab` and includes a header with the customer name, company, contact info, active/inactive status chip, and an accounting integration badge when synced with an external provider like QuickBooks.\n\n#### Stats Bar\n\nBelow the header, a clickable stats bar shows live aggregates:\n- **Open Estimates** — count of non-closed estimates\n- **Open Quotes** — count of active quotes\n- **Open Orders** — count of in-progress sales orders\n- **Active Jobs** — count of jobs currently on the kanban board\n- **Outstanding** — total dollar amount of unpaid invoices\n- **YTD Revenue** — total revenue from this customer in the current year\n\nClicking a stat switches to the corresponding tab for quick drill-down.\n\n#### Tab 1: Overview\n\nShows account details (name, company, email, phone, status, customer-since date), accounting integration info (provider, external ID, reference) when connected, and the Credit Status card.\n\n**Credit Status Card** displays:\n- Risk level chip (Low/Medium/High/OnHold)\n- Credit Hold banner with reason and Release button (when on hold)\n- Credit Limit, Open AR balance, Pending Orders total, Total Exposure, Available Credit, and Utilization percentage\n- Visual utilization bar that turns red when over limit\n- Place Hold button to block new orders with a required reason\n\n#### Tab 2: Contacts\n\nManage contact people for this customer. Each contact is displayed as a card with avatar, name (Last, First format), role, email, phone, and primary contact badge. You can add, edit, and remove contacts. Contact roles come from reference data (database-driven, not hardcoded).\n\n#### Tab 3: Interactions\n\nLog and track customer interactions — calls, emails, meetings, and notes. Each interaction records the type, subject, contact, who logged it, date, duration, and notes. Filter by contact or type. The table shows type (with icon), subject, contact name, logged-by user, date, and duration.\n\n#### Tab 4: Addresses\n\nView all addresses on file. Each address card shows the address type chip (Billing, Shipping, etc.), a Default badge if applicable, and the full address (line 1, line 2, city, state, ZIP, country).\n\n#### Tab 5: Estimates\n\nNon-binding ballpark figures for potential work. Each estimate has a title, description, estimated amount, valid-until date, status (Draft, Sent, Accepted, Declined, Expired), and notes. Estimates can be converted to formal Quotes via the convert button. The table shows title, amount, status, valid-until date, created date, and action buttons (convert to quote, delete).\n\n#### Tab 6: Quotes\n\nBinding, line-itemized price commitments. The table shows quote number, status, total amount, expiration date, and created date. Click a row to open the full quote detail dialog.\n\n#### Tab 7: Orders\n\nSales orders for this customer. The table shows order number, status (color-coded chip), total, requested date, and created date. Click to open the sales order detail dialog.\n\n#### Tab 8: Jobs\n\nAll kanban jobs linked to this customer. The table shows job title, stage (color-coded chip matching the kanban stage color), due date, and created date. Click to open the job detail dialog.\n\n#### Tab 9: Invoices\n\nInvoices issued to this customer. The table shows invoice number, status, total, due date, and created date. Click to open the invoice detail dialog.\n\n#### Tab 10: Activity\n\nChronological activity timeline showing all changes, comments, and events related to this customer. Uses the shared ActivityTimeline component.\n\n### How Customers Connect to Other Features\n\n**Quote-to-Cash Flow:** Customer → Estimate → Quote → Sales Order → Job → Shipment → Invoice → Payment. Every step in this chain links back to the customer record.\n\n**Jobs:** When a job is created on the kanban board, it can be assigned to a customer. The customer's Jobs tab shows all linked jobs.\n\n**Credit Management:** The credit status card monitors exposure (open AR + pending orders) against the credit limit. When a customer is on credit hold, new orders are blocked until the hold is released.\n\n**Accounting Integration:** When connected to QuickBooks or another accounting provider, the customer record syncs bidirectionally. The provider badge and external IDs appear in the Overview tab.\n\n### When to Use Customers\n\n- When onboarding a new customer for the first time\n- When looking up a customer's full history (orders, jobs, invoices)\n- When checking credit status before accepting a new order\n- When logging a phone call, email, or meeting with a customer contact\n- When managing billing and shipping addresses\n- When creating estimates or converting them to formal quotes","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Customers — Guided Tour",
            Slug = "customers-walkthrough",
            Summary = "A guided tour of the customers list page, detail page with 10 tabs, stats bar, contacts, addresses, estimates, credit status, and interactions.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/customers"]""",
            Tags = """["customers","walkthrough"]""",
            ContentJson = """{"appRoute":"/customers","startButtonLabel":"Tour Customers","steps":[{"element":"[data-testid='new-customer-btn']","popover":{"title":"Add Customer Button","description":"Click here to create a new customer. You'll enter the customer name, optional company name, email, and phone. After saving, you'll be taken to the new customer's detail page.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Customers","description":"Search by customer name, company name, email, or phone number. Press Enter to apply the search. Results update in the table below.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Active/Inactive Filter","description":"Filter the list to show only Active customers, only Inactive customers, or All. New customers default to Active status.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Customers Table","description":"Shows all customers with columns for Name, Company, Email, Phone, Active status (green/gray chip), Contact count, Job count, and Created date. Click any row to navigate to the customer detail page. Click column headers to sort.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Customers Field Reference",
            Slug = "customers-field-reference",
            Summary = "Complete reference for every field, button, status, validation rule, tab, table column, and action in the Customers module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/customers"]""",
            Tags = """["customers","reference"]""",
            ContentJson = """{"title":"Customers Field Reference","groups":[{"heading":"Customer Create/Edit Form Fields","items":[{"label":"Name (required)","value":"Text input. The customer's display name. Must not be empty. Max 200 characters."},{"label":"Company Name","value":"Text input, optional. The customer's business or company name. Displayed below the customer name in the detail header."},{"label":"Email","value":"Text input, optional. Must be a valid email format when provided. Max 200 characters. Displayed as a clickable mailto: link in the detail header."},{"label":"Phone","value":"Text input with phone mask, optional. Formats as (XXX) XXX-XXXX. Displayed as a clickable tel: link in the detail header."},{"label":"Is Active (edit only)","value":"Toggle, shown only in the edit dialog. Controls whether the customer appears in active-filtered views. Defaults to true for new customers."}]},{"heading":"Customer List Table Columns","items":[{"label":"Name","value":"Sortable. Customer display name."},{"label":"Company","value":"Sortable. Company name, or dash if not set."},{"label":"Email","value":"Sortable. Email address, or dash if not set."},{"label":"Phone","value":"Sortable. Phone number, or dash if not set."},{"label":"Active","value":"Sortable, filterable (enum). Green 'Active' chip or gray 'Inactive' chip."},{"label":"Contacts","value":"Sortable, center-aligned. Count of contacts linked to this customer."},{"label":"Jobs","value":"Sortable, center-aligned. Count of jobs linked to this customer."},{"label":"Created","value":"Sortable, date type. Customer creation date in MM/dd/yyyy format."}]},{"heading":"Stats Bar Metrics","items":[{"label":"Open Estimates","value":"Count of non-closed estimates for this customer. Clickable — switches to Estimates tab."},{"label":"Open Quotes","value":"Count of active quotes. Clickable — switches to Quotes tab."},{"label":"Open Orders","value":"Count of in-progress sales orders. Clickable — switches to Orders tab."},{"label":"Active Jobs","value":"Count of kanban jobs currently active. Clickable — switches to Jobs tab."},{"label":"Outstanding","value":"Total dollar amount of unpaid invoices, formatted as currency. Clickable — switches to Invoices tab."},{"label":"YTD Revenue","value":"Total revenue from this customer in the current year, formatted as currency. Not clickable."}]},{"heading":"Detail Page Tabs","items":[{"label":"Overview","value":"Account details, accounting integration info (provider, external ID, reference), and Credit Status card."},{"label":"Contacts","value":"Contact cards with avatar, name, role, email, phone, primary badge. Full CRUD (add, edit, delete)."},{"label":"Interactions","value":"Contact interaction log: calls, emails, meetings, notes. Filter by contact and type. Full CRUD."},{"label":"Addresses","value":"Address cards with type chip (Billing/Shipping/etc.), Default badge, and full address lines. Read-only display."},{"label":"Estimates","value":"Non-binding ballpark figures. DataTable with title, amount, status, valid-until, created. Create, edit, delete, convert to quote."},{"label":"Quotes","value":"Binding line-itemized quotes. DataTable with quote number, status, total, expiration date, created. Click to open quote detail dialog."},{"label":"Orders","value":"Sales orders. DataTable with order number, status, total, requested date, created. Click to open sales order detail dialog."},{"label":"Jobs","value":"Linked kanban jobs. DataTable with title, stage (color-coded chip), due date, created. Click to open job detail dialog."},{"label":"Invoices","value":"Issued invoices. DataTable with invoice number, status, total, due date, created. Click to open invoice detail dialog."},{"label":"Activity","value":"Chronological activity timeline of all changes, comments, and events. Uses shared ActivityTimeline component."}]},{"heading":"Contact Form Fields","items":[{"label":"First Name (required)","value":"Text input. Max 100 characters. Displayed in Last, First format throughout the app."},{"label":"Last Name (required)","value":"Text input. Max 100 characters."},{"label":"Email","value":"Text input, optional. Must be valid email format. Max 200 characters. Shown as clickable mailto: link on contact card."},{"label":"Phone","value":"Text input with phone mask, optional. Formats as (XXX) XXX-XXXX. Shown as clickable tel: link on contact card."},{"label":"Role","value":"Select dropdown, optional. Options loaded from reference data (contact_role group). '-- None --' is the null option."},{"label":"Primary Contact","value":"Toggle. When ON, marks this contact as the primary contact. Shown with a blue 'Primary' chip badge on the contact card."}]},{"heading":"Interaction Form Fields","items":[{"label":"Type (required)","value":"Select dropdown: Call, Email, Meeting, Note. Each type has a distinct icon in the table display."},{"label":"Contact","value":"Select dropdown, optional. Links the interaction to a specific contact. Options show all contacts for this customer plus '-- All Contacts --' null option."},{"label":"Subject (required)","value":"Text input. Max 200 characters. Brief description of the interaction."},{"label":"Date (required)","value":"Date picker. When the interaction occurred. Defaults to today."},{"label":"Duration (minutes)","value":"Number input, optional. Length of the interaction in minutes. Displayed formatted in the table."},{"label":"Notes","value":"Textarea, optional. 4 rows. Detailed notes about the interaction."}]},{"heading":"Interaction Table Columns","items":[{"label":"Type","value":"Sortable, filterable (enum). Chip with icon: phone (Call), email (Email), groups (Meeting), note (Note). Width 100px."},{"label":"Subject","value":"Sortable. The interaction subject text."},{"label":"Contact","value":"Sortable. Contact name (Last, First). Width 160px."},{"label":"Logged By","value":"Sortable. User who recorded the interaction. Width 160px."},{"label":"Date","value":"Sortable, date type. Interaction date in MM/dd/yyyy format. Width 120px."},{"label":"Duration","value":"Sortable, number type. Duration in minutes, formatted. Width 90px."},{"label":"Actions","value":"Edit and delete icon buttons. Width 80px."}]},{"heading":"Estimate Form Fields","items":[{"label":"Title (required)","value":"Text input. Max 300 characters. Brief title for the estimate."},{"label":"Description","value":"Textarea, optional. 2 rows. More detailed description of the estimate scope."},{"label":"Estimated Amount (required)","value":"Currency input with $ prefix. Must be >= 0."},{"label":"Valid Until","value":"Date picker, optional. Expiration date for the estimate."},{"label":"Status (edit only)","value":"Select dropdown, shown only when editing. Options: Draft, Sent, Accepted, Declined, Expired."},{"label":"Notes","value":"Textarea, optional. 2 rows. Internal notes."}]},{"heading":"Estimate Table Columns","items":[{"label":"Title","value":"Sortable. Estimate title text."},{"label":"Amount","value":"Sortable, number type, right-aligned. Estimated amount formatted as currency. Width 120px."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded chip: Draft, Sent, Accepted, Declined, Expired. Width 110px."},{"label":"Valid Until","value":"Sortable, date type. Expiration date in MM/dd/yyyy format. Width 110px."},{"label":"Created","value":"Sortable, date type. Creation date in MM/dd/yyyy format. Width 100px."},{"label":"Actions","value":"Convert to Quote button (forward icon, hidden if already converted) and Delete button. Width 100px."}]},{"heading":"Credit Status Card Fields","items":[{"label":"Risk Level","value":"Chip badge: Low (green), Medium (yellow), High (red), OnHold (red). Calculated from credit utilization and hold status."},{"label":"Credit Hold Banner","value":"Red banner shown when customer is on hold. Displays hold reason and a Release button."},{"label":"Credit Limit","value":"Currency value or 'None' if no limit set. The maximum credit exposure allowed."},{"label":"Open AR","value":"Currency value. Total of unpaid invoices (accounts receivable)."},{"label":"Pending Orders","value":"Currency value. Total of in-progress sales orders not yet invoiced."},{"label":"Total Exposure","value":"Currency value. Open AR + Pending Orders combined. Turns red when over limit."},{"label":"Available Credit","value":"Currency value. Credit Limit minus Total Exposure. Turns red when negative. Only shown when credit limit is set."},{"label":"Utilization","value":"Percentage. Total Exposure / Credit Limit × 100. Only shown when credit limit is set."},{"label":"Utilization Bar","value":"Visual progress bar. Turns red when utilization exceeds 100%."},{"label":"Place Hold Button","value":"Opens dialog to place credit hold with required reason (textarea, max 500 chars). Blocks new orders for this customer."},{"label":"Release Button","value":"Shown on hold banner. Removes the credit hold and unblocks new orders."}]},{"heading":"Address Card Fields","items":[{"label":"Type","value":"Chip badge showing address type: Billing, Shipping, or other configured types."},{"label":"Default","value":"Blue 'Default' chip badge shown on the default address."},{"label":"Line 1","value":"Primary street address line."},{"label":"Line 2","value":"Secondary address line (suite, unit, etc.). Only shown if set."},{"label":"City, State ZIP","value":"City name, 2-letter state code, and ZIP code on one line."},{"label":"Country","value":"Country name."}]},{"heading":"Quotes Tab Table Columns","items":[{"label":"Quote #","value":"Sortable. The quote reference number."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded chip: Draft, Sent, Accepted, Declined, Expired."},{"label":"Total","value":"Sortable, number type. Quote total formatted as currency."},{"label":"Expiration Date","value":"Sortable, date type. When the quote expires. MM/dd/yyyy format."},{"label":"Created","value":"Sortable, date type. Creation date. MM/dd/yyyy format."}]},{"heading":"Orders Tab Table Columns","items":[{"label":"Order #","value":"Sortable. The sales order reference number."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded status chip."},{"label":"Total","value":"Sortable, number type. Order total formatted as currency."},{"label":"Requested Date","value":"Sortable, date type. Customer's requested delivery date. MM/dd/yyyy format."},{"label":"Created","value":"Sortable, date type. Order creation date. MM/dd/yyyy format."}]},{"heading":"Jobs Tab Table Columns","items":[{"label":"Title","value":"Sortable. The job title."},{"label":"Stage","value":"Sortable. Color-coded chip matching the kanban board stage color via --chip-color custom property."},{"label":"Due Date","value":"Sortable, date type. Job due date. MM/dd/yyyy format."},{"label":"Created","value":"Sortable, date type. Job creation date. MM/dd/yyyy format."}]},{"heading":"Invoices Tab Table Columns","items":[{"label":"Invoice #","value":"Sortable. The invoice reference number."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded status chip."},{"label":"Total","value":"Sortable, number type. Invoice total formatted as currency."},{"label":"Due Date","value":"Sortable, date type. Payment due date. MM/dd/yyyy format."},{"label":"Created","value":"Sortable, date type. Invoice creation date. MM/dd/yyyy format."}]},{"heading":"Buttons and Actions","items":[{"label":"Add Customer (list page)","value":"Primary button. Opens quick-create dialog with Name, Company, Email, Phone. data-testid: new-customer-btn"},{"label":"Save (create dialog)","value":"Creates the customer. Disabled when form is invalid or save is in progress. Shows validation popover on hover. data-testid: customer-save-btn. After save, navigates to the new customer's detail page."},{"label":"Edit (detail page)","value":"Opens the edit dialog pre-filled with current values. Adds Is Active toggle not available in create."},{"label":"Archive (detail page)","value":"Archive icon button. Opens confirmation dialog with severity 'warn'. Archives (soft-deletes) the customer and navigates back to the list."},{"label":"Back to Customers","value":"Chevron-left link in the detail header. Navigates to /customers."},{"label":"Add Contact","value":"Primary button on Contacts tab. Opens contact create dialog."},{"label":"Edit Contact","value":"Edit icon button on each contact card. Opens pre-filled contact edit dialog."},{"label":"Remove Contact","value":"Delete icon button (danger style) on each contact card. Confirmation dialog required."},{"label":"Log Interaction","value":"Primary button on Interactions tab. Opens interaction create dialog."},{"label":"Edit Interaction","value":"Edit icon button in interactions table row. Opens pre-filled edit dialog."},{"label":"Delete Interaction","value":"Delete icon button (danger style) in interactions table row. Confirmation dialog required."},{"label":"New Estimate","value":"Primary button on Estimates tab. Opens estimate create dialog."},{"label":"Convert to Quote (estimate)","value":"Forward icon button on estimate row. Converts the estimate to a formal quote. Hidden if already converted."},{"label":"Delete Estimate","value":"Delete icon button (danger style) on estimate row. Confirmation dialog required."},{"label":"Place Hold","value":"Small button on Credit Status card. Opens hold reason dialog."},{"label":"Release Hold","value":"Small button on credit hold banner. Immediately releases the hold."}]},{"heading":"Validation Rules","items":[{"label":"Customer Name","value":"Required. Max 200 characters. Cannot be empty."},{"label":"Customer Email","value":"Optional. Must be valid email format when provided. Max 200 characters."},{"label":"Contact First Name","value":"Required. Max 100 characters."},{"label":"Contact Last Name","value":"Required. Max 100 characters."},{"label":"Contact Email","value":"Optional. Must be valid email format. Max 200 characters."},{"label":"Interaction Type","value":"Required. Must select one of: Call, Email, Meeting, Note."},{"label":"Interaction Subject","value":"Required. Max 200 characters."},{"label":"Interaction Date","value":"Required. Must select a date."},{"label":"Estimate Title","value":"Required. Max 300 characters."},{"label":"Estimated Amount","value":"Required. Must be a number >= 0."},{"label":"Credit Hold Reason","value":"Required when placing a hold. Max 500 characters."},{"label":"Submit button popover","value":"When form is invalid, hovering over Save shows a validation popover listing which fields need attention."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Customers Knowledge Check",
            Slug = "customers-quiz",
            Summary = "Test your knowledge of the Customers module: detail tabs, contacts, credit management, estimates, interactions, and the quote-to-cash flow.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/customers"]""",
            Tags = """["customers","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"cu1","text":"A new customer calls to request a quote. What is the first step in QB Engineer?","options":[{"id":"a","text":"Create a Quote directly from the Quotes page"},{"id":"b","text":"Navigate to Customers, click Add Customer, fill in their details, then create an estimate or quote from their detail page","isCorrect":true},{"id":"c","text":"Create a Job on the Kanban Board and assign the customer later"},{"id":"d","text":"Add them to the Leads module and wait for conversion"}],"explanation":"Start by creating the customer record. From their detail page, you can create estimates or quotes directly in the Estimates or Quotes tabs. This ensures all activity is linked to the customer."},{"id":"cu2","text":"You're on a customer's detail page and want to quickly see how many active jobs they have. Where do you look?","options":[{"id":"a","text":"Click the Jobs tab and count the rows in the table"},{"id":"b","text":"Check the stats bar — the 'Active Jobs' metric shows the count, and clicking it jumps to the Jobs tab","isCorrect":true},{"id":"c","text":"Run a report filtered by customer name"},{"id":"d","text":"Go to the Kanban Board and filter by customer"}],"explanation":"The stats bar below the customer header shows live aggregates including Active Jobs. Each stat is clickable — clicking 'Active Jobs' switches directly to the Jobs tab for details."},{"id":"cu3","text":"A customer's credit status shows 'Total Exposure' in red. What does this indicate?","options":[{"id":"a","text":"The customer has been on hold for more than 30 days"},{"id":"b","text":"The customer's combined open AR balance plus pending orders exceeds their credit limit","isCorrect":true},{"id":"c","text":"The customer has overdue invoices past 90 days"},{"id":"d","text":"The customer's account has been flagged for review"}],"explanation":"Total Exposure = Open AR + Pending Orders. When this exceeds the credit limit, the value displays in red to alert you that the customer is over their allowed credit."},{"id":"cu4","text":"You need to block a customer from placing new orders due to unpaid invoices. How do you do this?","options":[{"id":"a","text":"Set the customer's status to Inactive via the Edit dialog"},{"id":"b","text":"Delete all their open sales orders"},{"id":"c","text":"On the Overview tab, click 'Place Hold' on the Credit Status card and enter a reason","isCorrect":true},{"id":"d","text":"Contact your admin to disable their account"}],"explanation":"The Credit Status card on the Overview tab has a 'Place Hold' button. Clicking it opens a dialog where you must enter a reason. Once on hold, new orders are blocked until the hold is released."},{"id":"cu5","text":"A customer contact has been promoted and their role has changed. Where do you update this?","options":[{"id":"a","text":"Go to Admin → Reference Data and update their role entry"},{"id":"b","text":"Navigate to the customer's Contacts tab, click the edit icon on their contact card, and change the Role dropdown","isCorrect":true},{"id":"c","text":"Edit the contact directly from the customer list page"},{"id":"d","text":"The role field is read-only and cannot be changed after creation"}],"explanation":"On the Contacts tab, each contact card has an edit icon button. Click it to open the edit dialog where you can change any field including the Role dropdown. Role options come from reference data."},{"id":"cu6","text":"You had a phone call with a customer about an upcoming project. Where do you log this?","options":[{"id":"a","text":"Add a note to the Activity tab"},{"id":"b","text":"Create a new estimate on the Estimates tab"},{"id":"c","text":"Go to the Interactions tab, click 'Log Interaction', select Type: Call, fill in the subject, date, duration, and notes","isCorrect":true},{"id":"d","text":"Send an email from the Contacts tab"}],"explanation":"The Interactions tab is designed for tracking customer communications. Click 'Log Interaction', select Call as the type, and fill in the details including subject, date, duration, and any notes from the conversation."},{"id":"cu7","text":"An estimate has been accepted by the customer. What is the next step in the quote-to-cash flow?","options":[{"id":"a","text":"Create a job directly from the estimate"},{"id":"b","text":"Click the Convert to Quote button on the estimate row to create a formal, line-itemized quote","isCorrect":true},{"id":"c","text":"Change the estimate status to 'Converted' manually"},{"id":"d","text":"Delete the estimate and create a sales order instead"}],"explanation":"Estimates are non-binding ballpark figures. Once accepted, use the Convert to Quote button (forward icon) to create a formal, line-itemized quote. The quote can then be converted to a sales order. The convert button is hidden if the estimate has already been converted."},{"id":"cu8","text":"How many tabs does the customer detail page have, and which tab shows the Credit Status card?","options":[{"id":"a","text":"8 tabs; the Credit tab"},{"id":"b","text":"10 tabs; the Overview tab","isCorrect":true},{"id":"c","text":"10 tabs; the Invoices tab"},{"id":"d","text":"9 tabs; the Financials tab"}],"explanation":"The customer detail page has 10 tabs: Overview, Contacts, Interactions, Addresses, Estimates, Quotes, Orders, Jobs, Invoices, and Activity. The Credit Status card is displayed on the Overview tab alongside account details and integration info."},{"id":"cu9","text":"You want to find all inactive customers who were created in the last year. How do you filter the customer list?","options":[{"id":"a","text":"Set the Active filter to 'Inactive' — the table supports date column sorting to find recent entries","isCorrect":true},{"id":"b","text":"Run a search for 'inactive' in the search box"},{"id":"c","text":"Go to Reports and create a custom customer report"},{"id":"d","text":"You cannot filter inactive customers — they are hidden by default"}],"explanation":"The customer list page has an Active/Inactive filter dropdown. Set it to 'Inactive' to show only inactive customers, then sort by the Created column (date type) to find the most recent ones."},{"id":"cu10","text":"What information is displayed on a contact card in the Contacts tab?","options":[{"id":"a","text":"Just the contact's name and email"},{"id":"b","text":"Avatar with initials, name (Last, First format), role, email (mailto link), phone (tel link), and Primary badge if applicable","isCorrect":true},{"id":"c","text":"Name, job title, department, and office location"},{"id":"d","text":"Name, email, and a list of their recent interactions"}],"explanation":"Contact cards show an avatar (with initials), the name in Last, First format, their role (from reference data), clickable email and phone links, and a blue 'Primary' chip badge if they are the primary contact."},{"id":"cu11","text":"A customer's credit utilization bar is red and shows 115%. What actions can you take?","options":[{"id":"a","text":"Nothing — the system automatically blocks orders when over limit"},{"id":"b","text":"Place a credit hold via the Place Hold button, or increase the credit limit via the accounting system, or collect on outstanding invoices to reduce AR","isCorrect":true},{"id":"c","text":"Delete the oldest unpaid invoices to bring the balance down"},{"id":"d","text":"Archive the customer to prevent further orders"}],"explanation":"When over the credit limit, you can place a credit hold to formally block new orders (with a required reason), work with accounting to increase the credit limit, or focus on collecting outstanding invoices to reduce the AR balance and bring utilization back under 100%."},{"id":"cu12","text":"You want to share a direct link to a customer's Orders tab with a colleague. What URL format would you share?","options":[{"id":"a","text":"/customers?tab=orders&id=42"},{"id":"b","text":"/customers/42/orders","isCorrect":true},{"id":"c","text":"/customers/42?detail=orders"},{"id":"d","text":"/orders?customer=42"}],"explanation":"Customer detail pages use the URL pattern /customers/:id/:tab. Each tab is a route segment, so the Orders tab for customer 42 would be /customers/42/orders. This URL is bookmarkable and shareable."},{"id":"cu13","text":"What is the difference between an Estimate and a Quote in the customer detail?","options":[{"id":"a","text":"They are the same thing with different names"},{"id":"b","text":"Estimates are non-binding ballpark figures with a single amount; Quotes are binding, line-itemized commitments with per-item pricing","isCorrect":true},{"id":"c","text":"Estimates are for new customers; Quotes are for existing customers"},{"id":"d","text":"Estimates require approval; Quotes do not"}],"explanation":"Estimates are non-binding ballpark figures with a single estimated amount — quick and informal. Quotes are formal, binding commitments with individual line items (part, quantity, unit price). Estimates can be converted to Quotes when the customer is ready for a firm price."},{"id":"cu14","text":"You're filtering the Interactions tab and want to see only meetings with a specific contact. How?","options":[{"id":"a","text":"Type 'meeting' in the search box"},{"id":"b","text":"Set the Contact filter to the specific contact and the Type filter to 'Meeting'","isCorrect":true},{"id":"c","text":"Sort the table by Type column and scroll to Meeting rows"},{"id":"d","text":"Interactions cannot be filtered by both contact and type simultaneously"}],"explanation":"The Interactions tab toolbar has two filter dropdowns: Contact (to filter by specific contact or '-- All Contacts --') and Type (to filter by Call, Email, Meeting, Note, or '-- All Types --'). Both filters can be used simultaneously."},{"id":"cu15","text":"When you archive a customer, what happens to their data?","options":[{"id":"a","text":"All data is permanently deleted including contacts, orders, and invoices"},{"id":"b","text":"The customer record is soft-deleted — all history is preserved but the customer won't appear in active views","isCorrect":true},{"id":"c","text":"Only the customer name is kept; all related records are purged"},{"id":"d","text":"The customer is moved to a separate Archive database"}],"explanation":"Archiving uses soft delete (sets DeletedAt timestamp). All data is preserved — contacts, orders, jobs, invoices, activity history — nothing is lost. The customer simply won't appear in standard filtered views. This follows the app-wide rule of never hard-deleting records."}]}"""
        });

